13→/**
14→ * Extracts the earliest and latest top-level `timestamp` values from JSONL content.
15→ * Returns [earliest, latest] as ISO strings without trailing "Z", or [fallback, fallback]
16→ * if no valid timestamps are found.
17→ */
18→export function extractTimestampRange(
19→	content: string,
20→	fallback: string,
21→): [string, string] {
22→	const lines = content.split("\n");
23→	let earliest: number | undefined;
24→	let latest: number | undefined;
25→
26→	for (const line of lines) {
27→		const trimmed = line.trim();
28→		if (!trimmed) continue;
29→
30→		const tsMatch = trimmed.match(/"timestamp"\s*:\s*"([^"]+)"/);
31→		if (!tsMatch?.[1]) continue;
32→
33→		const ms = Date.parse(tsMatch[1]);
34→		if (Number.isNaN(ms)) continue;
35→
36→		if (earliest === undefined || ms < earliest) earliest = ms;
37→		if (latest === undefined || ms > latest) latest = ms;
38→	}
39→
40→	if (earliest === undefined || latest === undefined) {
41→		return [fallback, fallback];
42→	}
43→
44→	const fmt = (ms: number) => new Date(ms).toISOString().replace("Z", "");
45→	return [fmt(earliest), fmt(latest)];
46→}
